import scala.collection.mutable.PriorityQueue

def solve(value: Array[Long], limit: Array[Long]): Long = {
  val n = value.length
  val active = Array.fill(n)(true)
  val total = scala.collection.mutable.Map[Int, Long]()

  // Sort elements by value in descending order
  val sortedIndices = (0 until n).sorted((i, j) => value(j).compareTo(value(i)))

  var currentActiveCount = 0L

  for (i <- sortedIndices) {
    if (active(i)) {
      // Check if we can activate this element
      if (currentActiveCount < limit(i)) {
        // Activate the element
        total(i) = value(i)
        currentActiveCount += 1

        // Mark elements that become inactive
        for (j <- 0 until n) {
          if (active(j) && limit(j) <= currentActiveCount) {
            active(j) = false
          }
        }
      }
    }
  }

  // Sum all the values of activated elements
  var result = 0L
  for (i <- 0 until n) {
    if (active(i)) {
      result += total(i)
    }
  }

  result
}
